package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"
)

type Implementor struct {
	Repo       string `json:"repo"`
	File       string `json:"file"`
	StructName string `json:"struct_name"`
}

func main() {
	var implementors []Implementor

	// Search in /workspace/api
	implementors = append(implementors, findImplementorsInDir("/workspace/api", "kubernetes/api")...)
	implementors = append(implementors, findImplementorsInDir("/workspace/apimachinery", "kubernetes/apimachinery")...)

	// Write to JSON file
	data, _ := json.MarshalIndent(implementors, "", "  ")
	os.WriteFile("/workspace/implementors.json", data, 0644)

	fmt.Printf("Found %d implementors\n", len(implementors))
	for i, impl := range implementors {
		if i < 10 {
			fmt.Printf("%+v\n", impl)
		}
	}
}

func findImplementorsInDir(rootDir, repo string) []Implementor {
	var implementors []Implementor
	typePattern := regexp.MustCompile(`^type\s+(\w+)\s+struct\s*\{`)
	hasTypeMetaPattern := regexp.MustCompile(`metav1\.TypeMeta`)
	isListType := regexp.MustCompile(`List$`)

	filepath.Walk(rootDir, func(path string, info os.FileInfo, err error) error {
		if err != nil || info.IsDir() {
			return err
		}

		// Only process types.go files, exclude generated files
		if !strings.HasSuffix(path, "types.go") {
			return nil
		}
		if strings.Contains(path, "generated") || strings.Contains(path, "test") {
			return nil
		}

		file, err := os.Open(path)
		if err != nil {
			return nil
		}
		defer file.Close()

		scanner := bufio.NewScanner(file)
		inStruct := false
		currentType := ""
		structContent := ""
		lineNum := 0

		for scanner.Scan() {
			line := scanner.Text()
			lineNum++

			// Check for type declaration
			if match := typePattern.FindStringSubmatch(line); match != nil && !inStruct {
				currentType = match[1]
				inStruct = true
				structContent = line
				continue
			}

			if inStruct {
				structContent += "\n" + line

				// Look for closing brace
				if line == "}" {
					// Check if this struct has TypeMeta and is not a List type
					if hasTypeMetaPattern.MatchString(structContent) && !isListType.MatchString(currentType) {
						relPath, _ := filepath.Rel(rootDir, path)
						implementors = append(implementors, Implementor{
							Repo:       repo,
							File:       relPath,
							StructName: currentType,
						})
					}
					inStruct = false
					currentType = ""
					structContent = ""
				}
			}
		}

		return nil
	})

	return implementors
}
EOF
